%[text] # Panel models with no cross section linkages
%[text] Tutorial file for testing panel models
%[text:tableOfContents]{"heading":"**Table of Contents**"}
%%
%[text] ## Housekeeping
clear
close all
import separable.*  
%%
%[text] ## Convenience functions
percentiles = [10, 50, 90];

prctileFunc = @(x) prctile(x, percentiles, 2);

extremesFunc = @(x) [min(x, [], 2), max(x, [], 2)];

medianFunc = @(x) median(x, 2);

flatFunc = @(x) x(:, :);

defaultColors = get(0, "defaultAxesColorOrder");
%%
%[text] ## Number of Samples
numPresampled = 100;
%%
%[text] ## Prepare meta information for the models
%[text] 
%[text] Note that the meta information is common to all panel BVAR models, regardless of the specific estimator used.
%[text] The properties are as follows:
%[text] **endogenousConcepts** –  a list of endogenous variables, listed without the country suffix. Plays the same role as **endogenousNames** in plain BVARs
%[text] **units** – a list of countries/units that share the same endogenous variables

estimStart = datex("1972-Q1");
estimEnd = datex("2014-Q4");
estimSpan = datex.span(estimStart, estimEnd);

meta = Meta( ...
    endogenousConcepts=["YER", "HICSA", "STN"], ...
    units=["US", "EA"], ...
    exogenous=["Oil"], ...
    order=4, ...
    intercept=true, ...
    estimationSpan=estimSpan, ...
    identificationHorizon=12, ...
    shockConcepts=["DEM", "SUP", "POL"] ...
);


%%
%[text] ## Specifying and loading input data

inputTbl = tablex.fromFile("data/panel_data.csv");
dataH = DataHolder(meta, inputTbl);
%[text] ## 
%%
%[text] ## Reduced form models
%[text] 
%[text] #### OLS Mean Group Panel
%[text] There is no estimator specific settings.
estimatorR1 = estimator.MeanOLSPanel(meta);
%[text] ### 
%[text] #### Bayesian Pooled Panel with Normal-Wishart priors
%[text] There is no estimator specific settings.
%estimatorR1 = estimator.NormalWishartPanel(meta);
%[text] 
%[text] #### Zellner- Hong Random Effect Panel
%[text] There is no estimator specific settings.
%estimatorR1 = estimator.ZellnerHongPanel(meta);
%[text] 
%[text] #### Hierarchical Panel
%[text] **S0 (0.001)** – The shape of the Inverse Gamma distribution of overal tightness
%[text] **V0 (0.001)** – The scale of the Inverse Gamma distribution of overal tightness
% estimatorR1 = estimator.HierarchicalPanel(meta);
%[text] 
%[text] ### Creating the reduced form model

modelR1 = ReducedForm( ...
    meta=meta, ...
    dataHolder=dataH, ...
    estimator=estimatorR1 ...
);
%%
%[text] ## Estimation/sampling of the reduced form model 

modelR1.initialize();
info0 = modelR1.presample(numPresampled); %[output:21fc0294]
modelR1.Presampled{1}.beta %[output:0a86cfcc]

%[text] 
%%
%[text] ## Running Unconditional forecast 
%[text] 
%[text] ### Setting up the forecast range and run the forecast
fcastStart = datex.shift(modelR1.Meta.EstimationEnd, -10); %The forecast starts 10 periods prior to the end of the estimation span.
fcastEnd = datex.shift(modelR1.Meta.EstimationEnd, 0); %The forecast ends at the end of the estimation window.
fcastSpan = datex.span(fcastStart, fcastEnd);

fcastStart, fcastEnd %[output:36b74c31] %[output:704e0a19]

fcastTbx = modelR1.forecast(fcastSpan);
fcastPrctileTbx = tablex.apply(fcastTbx, prctileFunc);
fcastPrctileTbx = tablex.flatten(fcastPrctileTbx); %keeping only the pctiles set at the beginning of the file (10, 50, 90)


%[text] ### Visualize the unconditional forecast

chartpack.forecastPercentiles( ... %[output:group:4f240f0f] %[output:992b2586] %[output:4b980702] %[output:556377fd] %[output:56deecee]
    fcastPrctileTbx, modelR1, FigureTitle ="Unconditional forecast") %[output:group:4f240f0f] %[output:992b2586] %[output:4b980702] %[output:556377fd] %[output:56deecee]

%%
%[text] ## Identification
%[text] 
%[text] ### Cholesky
%[text] 
%[text] #### Setting up the identifier
identChol = identifier.Cholesky(order=[]);

modelS1 = Structural(reducedForm=modelR1, identifier=identChol);
modelS1.initialize();

info1 = modelS1.presample(numPresampled); %[output:48018c37]
modelS1.Presampled{1} %[output:0b19b7da]
%[text] #### 
%[text] #### Checking transition matrices
modelS1.Presampled{1}.IdentificationDraw %[output:31047a9d]
modelS1.Presampled{1}.IdentificationDraw.A{1,1} %[output:06cdfdcd]
modelS1.Presampled{1}.IdentificationDraw.A{2,1} %[output:7ce76b13]
%[text] #### 
%[text] #### Checking scaling matrix
modelS1.Presampled{1}.D %[output:866252ae]
modelS1.Presampled{2}.D %[output:0ead3128]

%%
%[text] ## Impulse responses (IRF)
%[text] ### 
%[text] ### Cholesky
respTbl1 = modelS1.simulateResponses(); %[output:46a21017]
respTbl1 = tablex.apply(respTbl1, prctileFunc);
respTbl1 = tablex.flatten(respTbl1);

respTbl1 %[output:371dff30]


chartpack.responsePercentiles( ...
    respTbl1, modelS1 ...
    , "figureTitle", "Shock responses (percentiles)" ...
);

%%
%[text] ## **Historical shock decomposition**
%[text] 

histContTbx = modelS1.calculateContributions();

tablex.getHigherDims(histContTbx) %[output:408bc32d]

histContMedTbx = tablex.apply(histContTbx, medianFunc);

chartpack.contributionsMedian( ...
    histContMedTbx, modelS1 ...
    , "figureTitle", "Shock contributions with Cholesky (median)" ...
);
%%
%[text] ## **Unconditional forecast shock decomposition**
%[text] 

[uncFcastTbl1, uncFcastContribTbl1] = modelS1.forecast( ...
    fcastSpan, ...
    contributions=true ...
);

tablex.getHigherDims(uncFcastContribTbl1)

contMedTbx = tablex.apply(uncFcastContribTbl1, medianFunc);

chartpack.contributionsMedian( ...
    contMedTbx,modelS1 ...
    , "figureTitle", "Unconditional forecast Shock contributions (median)" ...
);

%%
%[text] ## **FEVD**

fevdTbx = modelS1.calculateFEVD();

tablex.getHigherDims(fevdTbx)

fevdMedTbx = tablex.apply(fevdTbx, medianFunc);

chartpack.contributionsMedian( ...
    fevdMedTbx,modelS1 ...
    , "figureTitle", "FEVD (median)" ...
);

%%
%[text] ## Conditional forecast
%[text] 
%[text] ### Setting up the conditions and the forecast plan
condDataTbl = tablex.fromFile("data/condDataTblPanel.xlsx");
planTbl = tablex.readConditioningPlan("data/planTblPanel.xlsx");
%[text] ### 
%[text] ### Setting up the forecast range 
cfcastStart = datex.shift(modelR1.Meta.EstimationEnd, 1); %The forecast starts after the estimation span.
cfcastEnd = datex.shift(modelR1.Meta.EstimationEnd, 12); 
cfcastSpan = datex.span(cfcastStart, cfcastEnd);
%[text] ### 
%[text] ### Running conditional forecast with no simulation plan
[condFcastTbl1, condFcastContribTbl1] = modelS1.conditionalForecast( ...
    cfcastSpan, ...
    conditions=condDataTbl, ...
    plan=[], ...
    exogenousFrom = "conditions" ...
);

condFcastPrctilesTbl1 = tablex.apply(condFcastTbl1, prctileFunc);
%[text] ### 
%[text] ### Running conditional forecast with simulation plan
[condFcastTbl2, condFcastContribTbl2] = modelS1.conditionalForecast( ...
    cfcastSpan, ...
    conditions=condDataTbl, ...
    plan=planTbl, ...
    exogenousFrom = "conditions" ...
);

condFcastPrctilesTbl2 = tablex.apply(condFcastTbl2, prctileFunc);
%[text] ### 
%[text] ### Visualize the conditional forecast
chartpack.conditionalForecastPercentiles( ...
    condFcastPrctilesTbl1,modelS1 ...
    , "figureTitle", "Conditional forecast w/o plan (percentiles)" ...
);

chartpack.conditionalForecastPercentiles( ...
    condFcastPrctilesTbl2,modelS1 ...
    , "figureTitle", "Conditional forecast with plan (percentiles)" ...
);


